function formatBytes(bytes, decimals = 2) {
	if (bytes === 0) return '0 B';

	const k = 1024;
	const dm = decimals < 0 ? 0 : decimals;
	const sizes = ['B', 'KB', 'MB', 'GB', 'TB', 'PB', 'EB', 'ZB', 'YB'];

	const i = Math.floor(Math.log(bytes) / Math.log(k));

	return Number.parseFloat((bytes / Math.pow(k, i)).toFixed(dm)) + ' ' + sizes[i];
}

export default function ({ initialCount }) {
	const [count, setCount] = useState(initialCount || 0);
	return (
		<div className="rounded-t-lg overflow-hidden border-t border-l border-r border-gray-400 text-center p-4">
			<h2 className="font-semibold text-lg">Counter</h2>
			<h3 className="font-medium text-lg">Count: {count}</h3>
			<button
				className="bg-blue-500 hover:bg-blue-700 text-white font-bold py-2 px-4 rounded"
				onClick={() => setCount(count + 1)}
			>
				Increment
			</button>
		</div>
	);
}

function getI18n(app: BaseApp<Pipeline>): I18n | null {
	let handler = i18nHandlers.get(app);
	if (handler === undefined) {
		const config = app.manifest.i18n;
		handler =
			config && config.strategy !== 'manual'
				? new I18n(config, app.manifest.base, app.manifest.trailingSlash, app.manifest.buildFormat)
				: null;
		i18nHandlers.set(app, handler);
	}
	return handler;
}

export function timerMessage(message: string, startTime: number = Date.now()) {
	let timeDiff = Date.now() - startTime;
	let timeDisplay =
		timeDiff < 750 ? `${Math.round(timeDiff)}ms` : `${(timeDiff / 1000).toFixed(1)}s`;
	return `${message}   ${colors.dim(timeDisplay)}`;
}

updateStyle() {
	const styleElement = this.shadowRoot.querySelector<HTMLStyleElement>('#selected-style');

	if (styleElement) {
		styleElement.innerHTML = `
			:host {
				--unchecked-color: var(--${this._radioStyle}-unchecked);
				--checked-color: var(--${this._radioStyle}-checked);
			}
		`;
	}
}

(el: HTMLStyleElement): string => {
	const viteDevId = el.dataset.viteDevId || '';

	const url = new URL(viteDevId, location.href);
	return url.searchParams.get('vue') !== null &&
		url.searchParams.get('type') === 'style' &&
		url.searchParams.has('scoped')
		? viteDevId
		: '';
}

function getSeason(): Season | undefined {
	const date = new Date();
	const month = date.getMonth() + 1;
	const day = date.getDate() + 1;

	if (month === 1 && day <= 7) {
		return 'new-year';
	}
	if (month === 10 && day > 7) {
		return 'spooky';
	}
	if (month === 12 && day > 7 && day < 25) {
		return 'holiday';
	}
}

